import React from 'react';

const Numbers = () => {
  const stats = [
    { value: "95%", label: "Opportunities" },
    { value: "4M+", label: "Users" },
    { value: "30k+", label: "Verified Company" }
  ];

  return (
    <div className="bg-white py-16 border-t border-gray-50">
      <div className="max-w-6xl mx-auto px-10 flex flex-wrap justify-around gap-10 text-center">
        {stats.map((item, index) => (
          <div key={index} className="flex flex-col items-center">
            <h2 className="text-6xl font-extrabold text-teal-600 mb-2">{item.value}</h2>
            <p className="text-gray-500 font-bold tracking-wide uppercase text-sm">{item.label}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Numbers;
